 61ΓåÆ  if (timezone) {
 62ΓåÆ    try {
 63ΓåÆ      return new Date().toLocaleDateString("en-CA", { timeZone: timezone });
 64ΓåÆ    } catch { /* fall through to UTC */ }
 65ΓåÆ  }
 66ΓåÆ  return new Date().toISOString().slice(0, 10);
 67ΓåÆ}
