116ΓåÆ      const path = url.pathname;
117ΓåÆ      const tz = (request.cf as Record<string, unknown> | undefined)?.timezone as string | undefined;
118ΓåÆ      const method = request.method;
119ΓåÆ
120ΓåÆ      // ΓöÇΓöÇ GET /programs/default.json ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
121ΓåÆ      if (method === "GET" && path === "/programs/default.json") {
122ΓåÆ        return new Response(JSON.stringify(defaultProgramJson, null, 2), {
123ΓåÆ          headers: {
124ΓåÆ            "content-type": "application/json",
125ΓåÆ            "content-disposition": 'attachment; filename="default-program.json"',
126ΓåÆ          },
127ΓåÆ        });
128ΓåÆ      }
129ΓåÆ
130ΓåÆ      // ΓöÇΓöÇ GET / ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
131ΓåÆ      if (method === "GET" && path === "/") {
132ΓåÆ        const user = await getUser(env.DB, auth.userId);
133ΓåÆ        if (!user) {
134ΓåÆ          return htmlResponse(
135ΓåÆ            htmlShell({
136ΓåÆ              title: APP_NAME,
137ΓåÆ              subtitle: "Setup",
138ΓåÆ              body: `<div id="content">${setupPage()}</div>`,
139ΓåÆ            })
140ΓåÆ          );
141ΓåÆ        }
142ΓåÆ
143ΓåÆ        if (isSSERequest(request)) {
144ΓåÆ          return await handleTodaySSE(env, auth.userId, tz);
145ΓåÆ        }
146ΓåÆ
147ΓåÆ        const subtitle = await loadSubtitle(env.DB, auth.userId);
148ΓåÆ        return htmlResponse(
149ΓåÆ          htmlShell({
150ΓåÆ            title: APP_NAME,
151ΓåÆ            subtitle,
152ΓåÆ            activeTab: "today",
153ΓåÆ            ssePath: "/",
154ΓåÆ          })
155ΓåÆ        );
156ΓåÆ      }
157ΓåÆ
158ΓåÆ      // ΓöÇΓöÇ GET /progress ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
159ΓåÆ      if (method === "GET" && path === "/progress") {
160ΓåÆ        if (isSSERequest(request)) {
161ΓåÆ          return await handleProgressSSE(env, auth.userId);
162ΓåÆ        }
163ΓåÆ
164ΓåÆ        const subtitle = await loadSubtitle(env.DB, auth.userId);
165ΓåÆ        return htmlResponse(
166ΓåÆ          htmlShell({
