302ΓåÆasync function handleTodaySSE(env: Env, userId: string, tz?: string): Promise<Response> {
303ΓåÆ  const user = await getUser(env.DB, userId);
304ΓåÆ  if (!user) {
305ΓåÆ    return sseResponse(
306ΓåÆ      patchElements(setupPage(), { selector: "#content", mode: "inner" })
