310ΓåÆ  const program = await loadProgram(env.DB, userId);
311ΓåÆ  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
312ΓåÆ  const dailyRoutine = program.routines.find((r) => r.isDaily);
313ΓåÆ
314ΓåÆ  const items = await getQueueItems(env.DB, userId);
315ΓåÆ  const today = todayString(tz);
316ΓåÆ
317ΓåÆ  // Look up routine mappings for deep links
318ΓåÆ  const routineMappings = await getRoutineMappings(env.DB, userId);
319ΓåÆ  const routineToHevyId = new Map(
320ΓåÆ    routineMappings.map((m) => [m.program_routine_id, m.hevy_routine_id])
321ΓåÆ  );
322ΓåÆ
323ΓåÆ  const fragments: string[] = [];
324ΓåÆ
325ΓåÆ  const dailyDoneToday = dailyRoutine && user.daily_completed_date === today;
326ΓåÆ
327ΓåÆ  if (dailyRoutine && !dailyDoneToday) {
328ΓåÆ    fragments.push(patchElements(carsCard(dailyRoutine, routineToHevyId.get(dailyRoutine.id)), { selector: "#content", mode: "inner" }));
329ΓåÆ  }
330ΓåÆ
331ΓåÆ  // Hero session card ΓÇö next pending
332ΓåÆ  const nextItem = getNextRoutine(items);
333ΓåÆ  if (nextItem) {
334ΓåÆ    const routine = routineMap.get(nextItem.routine_id);
335ΓåÆ    if (routine) {
336ΓåÆ      const mode = (dailyRoutine && !dailyDoneToday) ? "append" : "inner";
