340ΓåÆ    }
341ΓåÆ  }
342ΓåÆ
343ΓåÆ  // Completed today
344ΓåÆ  const completed = getCompletedRoutines(items, today);
345ΓåÆ  const completedData = completed.map((item) => ({
346ΓåÆ    title: routineMap.get(item.routine_id)?.title ?? item.routine_id,
347ΓåÆ  }));
348ΓåÆ  if (dailyDoneToday) {
