354ΓåÆ    );
355ΓåÆ  }
356ΓåÆ
357ΓåÆ  // Upcoming (next 5 sessions)
358ΓåÆ  const template = program.weekTemplates.find((t) => t.id === user.template_id);
359ΓåÆ  if (template) {
360ΓåÆ    const pendingItems = items.filter((i) => i.status === "pending").sort((a, b) => a.position - b.position);
361ΓåÆ    // Skip the first pending (already shown as hero) for upcoming
362ΓåÆ    const upcomingPending = pendingItems.slice(1);
363ΓåÆ    const upcoming = computeUpcoming(upcomingPending, template, program.routines, 5);
364ΓåÆ    if (upcoming.length > 0) {
365ΓåÆ      fragments.push(
366ΓåÆ        patchElements(upcomingSection(upcoming), { selector: "#content", mode: "append" })
367ΓåÆ      );
368ΓåÆ    }
369ΓåÆ  }
370ΓåÆ
371ΓåÆ  // Sync button at the bottom
372ΓåÆ  fragments.push(
373ΓåÆ    patchElements(syncButton(), { selector: "#content", mode: "append" })
374ΓåÆ  );
375ΓåÆ
376ΓåÆ  return sseResponse(mergeFragments(fragments));
377ΓåÆ}
