477ΓåÆ/** POST /api/setup ΓÇö store program, sync Hevy, create user, generate queue */
478ΓåÆasync function handleSetup(request: Request, env: Env, userId: string, urlTemplateId?: string, tz?: string): Promise<Response> {
479ΓåÆ  let body: { apiKey?: string; startDate?: string; templateId?: string; programJson?: string } = {};
480ΓåÆ  try {
481ΓåÆ    body = (await request.json()) as typeof body;
482ΓåÆ  } catch {
483ΓåÆ    // Body may be empty ΓÇö that's OK, template ID comes from URL
484ΓåÆ  }
485ΓåÆ
486ΓåÆ  const templateId = urlTemplateId ?? body.templateId;
487ΓåÆ  const startDate = body.startDate || todayString(tz);
488ΓåÆ  const apiKey = body.apiKey || undefined;
489ΓåÆ  // Fall back to bundled default program if none uploaded
490ΓåÆ  const programJsonStr = body.programJson || JSON.stringify(defaultProgramJson);
491ΓåÆ
492ΓåÆ  if (!templateId) {
493ΓåÆ    return new Response("Template ID is required", { status: 400 });
494ΓåÆ  }
495ΓåÆ
496ΓåÆ  // Parse and validate program
497ΓåÆ  let program: Program;
498ΓåÆ  try {
499ΓåÆ    const parsed = JSON.parse(programJsonStr);
500ΓåÆ    const result = validateProgram(parsed);
501ΓåÆ    if (!result.valid) {
502ΓåÆ      return new Response(`Invalid program: ${result.errors.join(", ")}`, { status: 400 });
503ΓåÆ    }
504ΓåÆ    program = result.program;
505ΓåÆ  } catch {
506ΓåÆ    return new Response("Invalid program JSON", { status: 400 });
507ΓåÆ  }
508ΓåÆ
509ΓåÆ  const template = program.weekTemplates.find((t) => t.id === templateId);
510ΓåÆ  if (!template) {
511ΓåÆ    return new Response("Invalid template ID", { status: 400 });
512ΓåÆ  }
513ΓåÆ
514ΓåÆ  // Validate API key against Hevy before proceeding
515ΓåÆ  if (apiKey) {
516ΓåÆ    try {
517ΓåÆ      const client = new HevyClient(apiKey);
518ΓåÆ      await client.getExerciseTemplates(1, 1);
519ΓåÆ    } catch {
520ΓåÆ      return sseResponse(
521ΓåÆ        patchElements(
522ΓåÆ          `<div class="card"><p style="color:var(--orange)">Invalid Hevy API key. Check your key in Hevy Settings &gt; Developer and try again.</p></div>`,
523ΓåÆ          { selector: "#content", mode: "prepend" }
524ΓåÆ        )
525ΓåÆ      );
526ΓåÆ    }
527ΓåÆ  }
528ΓåÆ
529ΓåÆ  // h. Upsert user (must exist before program insert due to FK constraint)
530ΓåÆ  await upsertUser(env.DB, {
531ΓåÆ    id: userId,
532ΓåÆ    active_program: program.meta.title,
533ΓåÆ    template_id: templateId,
534ΓåÆ    start_date: startDate,
535ΓåÆ    hevy_api_key: apiKey,
536ΓåÆ  });
537ΓåÆ
538ΓåÆ  // a. Store program in D1
539ΓåÆ  await insertProgram(env.DB, userId, programJsonStr);
540ΓåÆ
541ΓåÆ  // b-g. Hevy exercise template & routine creation (only with API key)
542ΓåÆ  const routineIdMap = new Map<string, string>();
543ΓåÆ  if (apiKey) {
544ΓåÆ    const client = new HevyClient(apiKey);
545ΓåÆ
546ΓåÆ    // b. Fetch all Hevy exercise templates
547ΓåÆ    const hevyTemplates = await client.getAllExerciseTemplates();
548ΓåÆ
549ΓåÆ    // c. Auto-match our templates to Hevy's by normalized title
550ΓåÆ    const matched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
551ΓåÆ
552ΓåÆ    // d. Create custom Hevy exercise templates for unmatched
553ΓåÆ    const customCreated = new Set<string>();
554ΓåÆ    for (const et of program.exerciseTemplates) {
555ΓåÆ      if (!matched.has(et.id)) {
556ΓåÆ        const enums = mapToHevyEnums(et);
557ΓåÆ        const created = await client.createExerciseTemplate({
558ΓåÆ          title: et.title,
559ΓåÆ          exercise_type: enums.exerciseType,
560ΓåÆ          equipment_category: enums.equipmentCategory,
561ΓåÆ          muscle_group: enums.primaryMuscleGroup,
562ΓåÆ          other_muscles: enums.secondaryMuscleGroups,
563ΓåÆ        });
564ΓåÆ        matched.set(et.id, created.id);
565ΓåÆ        customCreated.add(et.id);
566ΓåÆ      }
567ΓåÆ    }
568ΓåÆ
569ΓåÆ    // e. Save all exercise template mappings
570ΓåÆ    for (const [programTemplateId, hevyTemplateId] of matched) {
571ΓåÆ      await upsertExerciseTemplateMapping(env.DB, {
572ΓåÆ        user_id: userId,
573ΓåÆ        program_template_id: programTemplateId,
574ΓåÆ        hevy_template_id: hevyTemplateId,
575ΓåÆ        is_custom: customCreated.has(programTemplateId) ? 1 : 0,
576ΓåÆ      });
577ΓåÆ    }
578ΓåÆ
579ΓåÆ    // f. Create or update Hevy routines with folder grouping + dedup
580ΓåÆ    const allMappings = await getExerciseTemplateMappings(env.DB, userId);
581ΓåÆ    const existingRoutineMappings = await getRoutineMappings(env.DB, userId);
582ΓåÆ    const existingMappingsMap = new Map(
583ΓåÆ      existingRoutineMappings.map((m) => [m.program_routine_id, m.hevy_routine_id])
584ΓåÆ    );
585ΓåÆ
586ΓåÆ    // Compute folder assignments and create/find folders
587ΓåÆ    const folderAssignments = computeFolderAssignments(program.routines, program.meta.title);
588ΓåÆ    const uniqueFolderNames = [...new Set(folderAssignments.map((a) => a.folderName))];
589ΓåÆ    const folderNameToId = new Map<string, number>();
590ΓåÆ    for (const name of uniqueFolderNames) {
591ΓåÆ      const folder = await client.getOrCreateRoutineFolder(name);
592ΓåÆ      folderNameToId.set(name, folder.id);
593ΓåÆ    }
594ΓåÆ
595ΓåÆ    // Fetch existing Hevy routines for dedup by title+folder
596ΓåÆ    const existingHevyRoutines = await client.getAllRoutines();
597ΓåÆ
598ΓåÆ    // Reconcile: decide create vs update for each routine
599ΓåÆ    const reconciliations = reconcileRoutines(
600ΓåÆ      folderAssignments, existingHevyRoutines, folderNameToId, existingMappingsMap
601ΓåÆ    );
602ΓåÆ
603ΓåÆ    for (const recon of reconciliations) {
604ΓåÆ      const routine = program.routines.find((r) => r.id === recon.programRoutineId)!;
605ΓåÆ      const payload = buildRoutinePayload(routine, allMappings);
606ΓåÆ      const folderId = folderNameToId.get(recon.folderName)!;
607ΓåÆ
608ΓåÆ      if (recon.action === "update" && recon.existingHevyRoutineId) {
609ΓåÆ        await client.updateRoutine(recon.existingHevyRoutineId, {
610ΓåÆ          title: payload.title,
611ΓåÆ          exercises: payload.exercises,
612ΓåÆ        });
613ΓåÆ        routineIdMap.set(routine.id, recon.existingHevyRoutineId);
614ΓåÆ      } else {
615ΓåÆ        const created = await client.createRoutine({
616ΓåÆ          title: payload.title,
617ΓåÆ          folder_id: folderId,
618ΓåÆ          exercises: payload.exercises,
619ΓåÆ        });
620ΓåÆ        routineIdMap.set(routine.id, created.id);
621ΓåÆ      }
622ΓåÆ    }
623ΓåÆ
624ΓåÆ    // g. Save all routine mappings
625ΓåÆ    for (const [programRoutineId, hevyRoutineId] of routineIdMap) {
626ΓåÆ      await upsertRoutineMapping(env.DB, {
627ΓåÆ        user_id: userId,
628ΓåÆ        program_routine_id: programRoutineId,
629ΓåÆ        hevy_routine_id: hevyRoutineId,
630ΓåÆ      });
631ΓåÆ    }
632ΓåÆ  }
633ΓåÆ
634ΓåÆ  // i. Generate queue playlist
635ΓåÆ  const weeks = program.meta.durationWeeks || 8;
636ΓåÆ  const playlist = generatePlaylist(template, program.routines, weeks);
637ΓåÆ  if (playlist.length > 0) {
638ΓåÆ    await insertQueueItems(env.DB, userId, playlist);
639ΓåÆ  }
640ΓåÆ
641ΓåÆ  // j. Bulk-set hevy_routine_id on queue items via routine_mappings
642ΓåÆ  if (apiKey) {
643ΓåÆ    await bulkSetQueueItemRoutineIds(env.DB, userId, routineIdMap);
644ΓåÆ  }
645ΓåÆ
646ΓåÆ  // k. Redirect to Today
647ΓåÆ  return sseResponse(executeScript("window.location.href = '/'"));
648ΓåÆ}
