752ΓåÆ/** POST /api/cleanup-routines ΓÇö delete duplicate routines from Hevy */
753ΓåÆasync function handleCleanupRoutines(env: Env, userId: string): Promise<Response> {
754ΓåÆ  const user = await getUser(env.DB, userId);
755ΓåÆ  if (!user || !user.hevy_api_key) {
756ΓåÆ    return sseResponse(
757ΓåÆ      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
758ΓåÆ        selector: "#content",
759ΓåÆ        mode: "prepend",
760ΓåÆ      })
761ΓåÆ    );
762ΓåÆ  }
763ΓåÆ
764ΓåÆ  const client = new HevyClient(user.hevy_api_key);
765ΓåÆ  const allRoutines = await client.getAllRoutines();
766ΓåÆ
767ΓåÆ  // Group by title+folder, find duplicates
768ΓåÆ  const byKey = new Map<string, typeof allRoutines>();
769ΓåÆ  for (const r of allRoutines) {
770ΓåÆ    const key = `${r.title}::${r.folder_id ?? "none"}`;
771ΓåÆ    const list = byKey.get(key) ?? [];
772ΓåÆ    list.push(r);
773ΓåÆ    byKey.set(key, list);
774ΓåÆ  }
775ΓåÆ
776ΓåÆ  const toDelete: string[] = [];
777ΓåÆ  for (const [, routines] of byKey) {
778ΓåÆ    if (routines.length > 1) {
779ΓåÆ      // Keep the most recently updated, delete the rest
780ΓåÆ      routines.sort((a, b) => (b.updated_at ?? "").localeCompare(a.updated_at ?? ""));
781ΓåÆ      toDelete.push(...routines.slice(1).map((r) => r.id));
782ΓåÆ    }
783ΓåÆ  }
784ΓåÆ
785ΓåÆ  let deleted = 0;
786ΓåÆ  let failed = 0;
787ΓåÆ  for (const id of toDelete) {
788ΓåÆ    try {
789ΓåÆ      await client.deleteRoutine(id);
790ΓåÆ      deleted++;
791ΓåÆ    } catch {
792ΓåÆ      failed++;
793ΓåÆ    }
794ΓåÆ  }
795ΓåÆ
796ΓåÆ  const msg = toDelete.length === 0
797ΓåÆ    ? "No duplicates found."
798ΓåÆ    : `Cleaned up ${deleted} duplicate(s)${failed > 0 ? `, ${failed} failed` : ""}.`;
799ΓåÆ
800ΓåÆ  return sseResponse(
801ΓåÆ    patchElements(
802ΓåÆ      `<div class="card"><p style="color:var(--green)">${escapeHtml(msg)}</p></div>`,
803ΓåÆ      { selector: "#content", mode: "prepend" }
804ΓåÆ    )
805ΓåÆ  );
806ΓåÆ}
