891ΓåÆ/** POST /api/complete/:id ΓÇö manual complete, re-render today */
892ΓåÆasync function handleManualComplete(
893ΓåÆ  env: Env,
894ΓåÆ  userId: string,
895ΓåÆ  itemId: number,
896ΓåÆ  tz?: string
897ΓåÆ): Promise<Response> {
898ΓåÆ  if (!Number.isInteger(itemId)) {
899ΓåÆ    return new Response("Invalid item ID", { status: 400 });
900ΓåÆ  }
901ΓåÆ  const today = todayString(tz);
902ΓåÆ  await markQueueItemCompletedForUser(env.DB, itemId, userId, today);
903ΓåÆ  return await handleTodaySSE(env, userId, tz);
904ΓåÆ}
