 4ΓåÆexport interface UpcomingItem {
 5ΓåÆ  type: "routine" | "spacer";
 6ΓåÆ  routineId?: string;
 7ΓåÆ  title: string;
 8ΓåÆ  exerciseCount?: number;
 9ΓåÆ  color?: string;
10ΓåÆ}
