12ΓåÆexport function computeUpcoming(
13ΓåÆ  pendingItems: QueueItemRow[],
14ΓåÆ  template: WeekTemplate,
15ΓåÆ  routines: Routine[],
16ΓåÆ  maxSessions: number
17ΓåÆ): UpcomingItem[] {
18ΓåÆ  const routineMap = new Map(routines.map((r) => [r.id, r]));
19ΓåÆ
20ΓåÆ  // Build the template rhythm: which day indices are spacers vs routines
21ΓåÆ  const templateRhythm: Array<{ type: "routine" | "spacer"; routineId?: string }> = [];
22ΓåÆ  for (const day of template.days) {
23ΓåÆ    const mainIds = (day.routineIDs ?? []).filter((rid) => {
24ΓåÆ      const r = routineMap.get(rid);
25ΓåÆ      return r && !r.isDaily;
26ΓåÆ    });
27ΓåÆ    if (mainIds.length === 0 && (day.routineIDs ?? []).length > 0) {
28ΓåÆ      templateRhythm.push({ type: "spacer" });
29ΓåÆ    } else if (mainIds.length > 0) {
30ΓåÆ      for (const rid of mainIds) {
31ΓåÆ        templateRhythm.push({ type: "routine", routineId: rid });
32ΓåÆ      }
33ΓåÆ    }
34ΓåÆ  }
35ΓåÆ
36ΓåÆ  const result: UpcomingItem[] = [];
37ΓåÆ  let rhythmIndex = 0;
38ΓåÆ  let sessionCount = 0;
39ΓåÆ
40ΓåÆ  const firstPending = pendingItems[0];
41ΓåÆ  if (firstPending) {
42ΓåÆ    for (let i = 0; i < templateRhythm.length; i++) {
43ΓåÆ      if (templateRhythm[i].routineId === firstPending.routine_id) {
44ΓåÆ        rhythmIndex = i;
45ΓåÆ        break;
46ΓåÆ      }
47ΓåÆ    }
48ΓåÆ  }
49ΓåÆ
50ΓåÆ  let pendingIdx = 0;
51ΓåÆ  while (sessionCount < maxSessions && pendingIdx < pendingItems.length) {
52ΓåÆ    const rhythmSlot = templateRhythm[rhythmIndex % templateRhythm.length];
53ΓåÆ
54ΓåÆ    if (rhythmSlot.type === "spacer") {
55ΓåÆ      result.push({ type: "spacer", title: "CARs only" });
56ΓåÆ    } else {
57ΓåÆ      const item = pendingItems[pendingIdx];
58ΓåÆ      const routine = routineMap.get(item.routine_id);
59ΓåÆ      result.push({
60ΓåÆ        type: "routine",
61ΓåÆ        routineId: item.routine_id,
62ΓåÆ        title: routine?.title ?? item.routine_id,
63ΓåÆ        exerciseCount: routine?.exercises.length,
64ΓåÆ        color: routine?.color,
65ΓåÆ      });
66ΓåÆ      pendingIdx++;
67ΓåÆ      sessionCount++;
68ΓåÆ    }
69ΓåÆ
70ΓåÆ    rhythmIndex++;
71ΓåÆ  }
72ΓåÆ
73ΓåÆ  return result;
74ΓåÆ}
