  8ΓåÆ/**
  9ΓåÆ * Parse a sets string like "3├ù8", "3├ù30 sec", "2├ù45 sec", "3├ù1 min"
 10ΓåÆ * into an array of HevySet objects.
 11ΓåÆ *
 12ΓåÆ * - Patterns containing "sec" or "min" produce duration_seconds sets.
 13ΓåÆ * - All other patterns produce reps sets.
 14ΓåÆ */
 15ΓåÆfunction parseSetsString(setsStr: string): HevySet[] {
 16ΓåÆ  // Normalise the multiplication sign ΓÇö programs may use ├ù (U+00D7) or x
 17ΓåÆ  const normalised = setsStr.replace(/├ù/g, "x");
 18ΓåÆ
 19ΓåÆ  // Match "NxM sec", "NxM min", or "NxM"
 20ΓåÆ  const match = normalised.match(/^(\d+)\s*x\s*(\d+(?:\.\d+)?)\s*(sec|min)?/i);
 21ΓåÆ  if (!match) {
 22ΓåÆ    // Fallback: return a single normal set with no values
 23ΓåÆ    return [{ type: "normal", reps: null }];
 24ΓåÆ  }
 25ΓåÆ
 26ΓåÆ  const count = parseInt(match[1], 10);
 27ΓåÆ  const value = parseFloat(match[2]);
 28ΓåÆ  const unit = match[3]?.toLowerCase();
 29ΓåÆ
 30ΓåÆ  const isDuration = unit === "sec" || unit === "min";
 31ΓåÆ  const duration_seconds = isDuration
 32ΓåÆ    ? unit === "min"
 33ΓåÆ      ? Math.round(value * 60)
 34ΓåÆ      : Math.round(value)
 35ΓåÆ    : undefined;
 36ΓåÆ
 37ΓåÆ  const sets: HevySet[] = [];
 38ΓåÆ  for (let i = 0; i < count; i++) {
 39ΓåÆ    if (isDuration) {
 40ΓåÆ      sets.push({ type: "normal", reps: null, duration_seconds });
 41ΓåÆ    } else {
 42ΓåÆ      const reps = Math.round(value);
 43ΓåÆ      sets.push({ type: "normal", reps });
 44ΓåÆ    }
 45ΓåÆ  }
 46ΓåÆ  return sets;
 47ΓåÆ}
