195ΓåÆ/**
196ΓåÆ * Match Hevy workouts to queue items by comparing each workout's routine ID
197ΓåÆ * (obtained via `getRoutineId`) to the `hevy_routine_id` stored on the queue
198ΓåÆ * item.
199ΓåÆ *
200ΓåÆ * Each workout is matched to at most one queue item.
201ΓåÆ */
202ΓåÆexport function matchCompletions(
203ΓåÆ  items: Pick<QueueItemRow, "id" | "hevy_routine_id">[],
204ΓåÆ  workouts: HevyWorkout[],
205ΓåÆ  getRoutineId: (workout: HevyWorkout) => string | null
206ΓåÆ): CompletionMatch[] {
207ΓåÆ  // Build a map: routine_id ΓåÆ queue item id (first match wins)
208ΓåÆ  const routineToItem = new Map<string, number>();
209ΓåÆ  for (const item of items) {
210ΓåÆ    if (item.hevy_routine_id && !routineToItem.has(item.hevy_routine_id)) {
211ΓåÆ      routineToItem.set(item.hevy_routine_id, item.id);
212ΓåÆ    }
213ΓåÆ  }
214ΓåÆ
215ΓåÆ  const matches: CompletionMatch[] = [];
216ΓåÆ  const usedItems = new Set<number>();
217ΓåÆ
218ΓåÆ  for (const workout of workouts) {
219ΓåÆ    const routineId = getRoutineId(workout);
220ΓåÆ    if (!routineId) continue;
221ΓåÆ
222ΓåÆ    const itemId = routineToItem.get(routineId);
223ΓåÆ    if (itemId !== undefined && !usedItems.has(itemId)) {
224ΓåÆ      matches.push({ queueItemId: itemId, workoutId: workout.id });
225ΓåÆ      usedItems.add(itemId);
226ΓåÆ    }
227ΓåÆ  }
228ΓåÆ
229ΓåÆ  return matches;
230ΓåÆ}
