246ΓåÆ      // ΓöÇΓöÇ 404 ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
247ΓåÆ      return new Response("Not Found", { status: 404 });
248ΓåÆ    } catch (err) {
249ΓåÆ      if (err instanceof Response) return err;
250ΓåÆ      const message = err instanceof Error ? err.message : "Internal Server Error";
251ΓåÆ      const stack = err instanceof Error ? err.stack : "";
252ΓåÆ      console.error("Unhandled error:", message, stack);
253ΓåÆ      return new Response(message, { status: 500 });
254ΓåÆ    }
255ΓåÆ  },
256ΓåÆ};
