302ΓåÆasync function handleTodaySSE(env: Env, userId: string, tz?: string): Promise<Response> {
303ΓåÆ  const user = await getUser(env.DB, userId);
304ΓåÆ  if (!user) {
305ΓåÆ    return sseResponse(
306ΓåÆ      patchElements(setupPage(), { selector: "#content", mode: "inner" })
307ΓåÆ    );
308ΓåÆ  }
309ΓåÆ
310ΓåÆ  const program = await loadProgram(env.DB, userId);
311ΓåÆ  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
312ΓåÆ  const dailyRoutine = program.routines.find((r) => r.isDaily);
313ΓåÆ
314ΓåÆ  const items = await getQueueItems(env.DB, userId);
315ΓåÆ  const today = todayString(tz);
316ΓåÆ
317ΓåÆ  // Look up routine mappings for deep links
318ΓåÆ  const routineMappings = await getRoutineMappings(env.DB, userId);
319ΓåÆ  const routineToHevyId = new Map(
320ΓåÆ    routineMappings.map((m) => [m.program_routine_id, m.hevy_routine_id])
321ΓåÆ  );
322ΓåÆ
323ΓåÆ  const fragments: string[] = [];
324ΓåÆ
325ΓåÆ  const dailyDoneToday = dailyRoutine && user.daily_completed_date === today;
326ΓåÆ
327ΓåÆ  if (dailyRoutine && !dailyDoneToday) {
328ΓåÆ    fragments.push(patchElements(carsCard(dailyRoutine, routineToHevyId.get(dailyRoutine.id)), { selector: "#content", mode: "inner" }));
329ΓåÆ  }
330ΓåÆ
331ΓåÆ  // Hero session card ΓÇö next pending
332ΓåÆ  const nextItem = getNextRoutine(items);
333ΓåÆ  if (nextItem) {
334ΓåÆ    const routine = routineMap.get(nextItem.routine_id);
335ΓåÆ    if (routine) {
336ΓåÆ      const mode = (dailyRoutine && !dailyDoneToday) ? "append" : "inner";
337ΓåÆ      fragments.push(
338ΓåÆ        patchElements(heroRoutineCard(routine, nextItem), { selector: "#content", mode })
339ΓåÆ      );
340ΓåÆ    }
341ΓåÆ  }
342ΓåÆ
343ΓåÆ  // Completed today
344ΓåÆ  const completed = getCompletedRoutines(items, today);
345ΓåÆ  const completedData = completed.map((item) => ({
346ΓåÆ    title: routineMap.get(item.routine_id)?.title ?? item.routine_id,
347ΓåÆ  }));
348ΓåÆ  if (dailyDoneToday) {
349ΓåÆ    completedData.unshift({ title: dailyRoutine.title });
350ΓåÆ  }
351ΓåÆ  if (completedData.length > 0) {
352ΓåÆ    fragments.push(
353ΓåÆ      patchElements(completedSection(completedData), { selector: "#content", mode: "append" })
354ΓåÆ    );
355ΓåÆ  }
356ΓåÆ
357ΓåÆ  // Upcoming (next 5 sessions)
358ΓåÆ  const template = program.weekTemplates.find((t) => t.id === user.template_id);
359ΓåÆ  if (template) {
360ΓåÆ    const pendingItems = items.filter((i) => i.status === "pending").sort((a, b) => a.position - b.position);
361ΓåÆ    // Skip the first pending (already shown as hero) for upcoming
362ΓåÆ    const upcomingPending = pendingItems.slice(1);
363ΓåÆ    const upcoming = computeUpcoming(upcomingPending, template, program.routines, 5);
364ΓåÆ    if (upcoming.length > 0) {
365ΓåÆ      fragments.push(
366ΓåÆ        patchElements(upcomingSection(upcoming), { selector: "#content", mode: "append" })
367ΓåÆ      );
368ΓåÆ    }
369ΓåÆ  }
370ΓåÆ
371ΓåÆ  // Sync button at the bottom
372ΓåÆ  fragments.push(
373ΓåÆ    patchElements(syncButton(), { selector: "#content", mode: "append" })
374ΓåÆ  );
375ΓåÆ
376ΓåÆ  return sseResponse(mergeFragments(fragments));
377ΓåÆ}
