656ΓåÆ        selector: "#content",
657ΓåÆ        mode: "inner",
658ΓåÆ      })
659ΓåÆ    );
660ΓåÆ  }
661ΓåÆ
662ΓåÆ  // Look up existing routine mapping from setup
663ΓåÆ  const routineMappings = await getRoutineMappings(env.DB, userId);
664ΓåÆ  const mapping = routineMappings.find((m) => m.program_routine_id === routineId);
665ΓåÆ
666ΓåÆ  if (mapping) {
667ΓåÆ    // Routine already exists in Hevy ΓÇö open it directly
668ΓåÆ    return sseResponse(
669ΓåÆ      executeScript(`window.open('https://hevy.com/routine/${mapping.hevy_routine_id}', '_blank')`)
670ΓåÆ    );
671ΓåÆ  }
672ΓåÆ
673ΓåÆ  // Fallback: no mapping exists (edge case ΓÇö setup didn't create this routine)
674ΓåÆ  const program = await loadProgram(env.DB, userId);
675ΓåÆ  const routine = program.routines.find((r) => r.id === routineId);
676ΓåÆ  if (!routine) {
677ΓåÆ    return new Response("Routine not found", { status: 404 });
678ΓåÆ  }
679ΓåÆ
680ΓåÆ  const client = new HevyClient(user.hevy_api_key);
681ΓåÆ
682ΓåÆ  // Get or auto-create exercise template mappings
683ΓåÆ  let mappings = await getExerciseTemplateMappings(env.DB, userId);
684ΓåÆ  if (mappings.length === 0) {
685ΓåÆ    try {
686ΓåÆ      const hevyTemplates = await client.getAllExerciseTemplates();
687ΓåÆ      const autoMatched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
688ΓåÆ
689ΓåÆ      for (const [programTemplateId, hevyTemplateId] of autoMatched) {
690ΓåÆ        await upsertExerciseTemplateMapping(env.DB, {
691ΓåÆ          user_id: userId,
692ΓåÆ          program_template_id: programTemplateId,
693ΓåÆ          hevy_template_id: hevyTemplateId,
694ΓåÆ          is_custom: 0,
695ΓåÆ        });
696ΓåÆ      }
697ΓåÆ      mappings = await getExerciseTemplateMappings(env.DB, userId);
698ΓåÆ    } catch {
699ΓåÆ      // If auto-match fails, continue with empty mappings
700ΓåÆ    }
701ΓåÆ  }
702ΓåÆ
703ΓåÆ  const payload = buildRoutinePayload(routine, mappings);
704ΓåÆ
705ΓåÆ  if (payload.exercises.length === 0) {
706ΓåÆ    return sseResponse(
707ΓåÆ      patchElements(
708ΓåÆ        `<div class="card"><p style="color:var(--orange)">Cannot push: no exercises could be mapped to Hevy templates. ${payload.unmapped.length} unmapped exercise(s).</p></div>`,
709ΓåÆ        { selector: "#content", mode: "prepend" }
710ΓåÆ      )
711ΓåÆ    );
712ΓåÆ  }
713ΓåÆ
714ΓåÆ  try {
715ΓåÆ    const folder = await client.getOrCreateRoutineFolder(program.meta.title);
716ΓåÆ    const created = await client.createRoutine({
717ΓåÆ      title: payload.title,
718ΓåÆ      folder_id: folder.id,
719ΓåÆ      exercises: payload.exercises,
720ΓåÆ    });
721ΓåÆ
722ΓåÆ    // Save the mapping so future pushes use the existing routine
723ΓåÆ    await upsertRoutineMapping(env.DB, {
724ΓåÆ      user_id: userId,
725ΓåÆ      program_routine_id: routineId,
726ΓåÆ      hevy_routine_id: created.id,
727ΓåÆ    });
728ΓåÆ
729ΓåÆ    // Also update the queue item if there is one
730ΓåÆ    const items = await getQueueItems(env.DB, userId);
731ΓåÆ    const queueItem = items.find(
732ΓåÆ      (i) => i.routine_id === routineId && i.status === "pending"
733ΓåÆ    );
734ΓåÆ    if (queueItem) {
735ΓåÆ      await updateQueueItemHevyRoutineId(env.DB, queueItem.id, created.id);
736ΓåÆ    }
737ΓåÆ
738ΓåÆ    return sseResponse(
739ΓåÆ      executeScript(`window.open('https://hevy.com/routine/${created.id}', '_blank')`)
740ΓåÆ    );
741ΓåÆ  } catch (err) {
742ΓåÆ    const msg = escapeHtml(err instanceof Error ? err.message : "Push failed");
743ΓåÆ    return sseResponse(
744ΓåÆ      patchElements(
745ΓåÆ        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
746ΓåÆ        { selector: "#content", mode: "prepend" }
747ΓåÆ      )
748ΓåÆ    );
749ΓåÆ  }
750ΓåÆ}
