808ΓåÆ/** POST /api/pull ΓÇö pull completions from Hevy */
809ΓåÆasync function handlePull(env: Env, userId: string, tz?: string): Promise<Response> {
810ΓåÆ  const user = await getUser(env.DB, userId);
811ΓåÆ  if (!user || !user.hevy_api_key) {
812ΓåÆ    return sseResponse(
813ΓåÆ      patchElements(`<div class="card"><p>Connect your Hevy API key first.</p></div>`, {
814ΓåÆ        selector: "#content",
815ΓåÆ        mode: "inner",
816ΓåÆ      })
817ΓåÆ    );
818ΓåÆ  }
819ΓåÆ
820ΓåÆ  const program = await loadProgram(env.DB, userId);
821ΓåÆ  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
822ΓåÆ  const client = new HevyClient(user.hevy_api_key);
823ΓåÆ
824ΓåÆ  try {
825ΓåÆ    const [workouts, items] = await Promise.all([
826ΓåÆ      client.getRecentWorkouts(),
827ΓåÆ      getQueueItems(env.DB, userId),
828ΓåÆ    ]);
829ΓåÆ
830ΓåÆ    // Skip workouts already matched to a completed queue item
831ΓåÆ    const usedWorkoutIds = new Set(
832ΓåÆ      items.filter((i) => i.hevy_workout_id).map((i) => i.hevy_workout_id)
833ΓåÆ    );
834ΓåÆ    const newWorkouts = workouts.filter((w) => !usedWorkoutIds.has(w.id));
835ΓåÆ
836ΓåÆ    const pendingItems = items.filter((i) => i.status === "pending" && i.hevy_routine_id);
837ΓåÆ
838ΓåÆ    const nameToRoutineId = new Map<string, string>();
839ΓåÆ    for (const item of pendingItems) {
840ΓåÆ      const routine = routineMap.get(item.routine_id);
841ΓåÆ      if (routine && item.hevy_routine_id) {
842ΓåÆ        nameToRoutineId.set(routine.title, item.hevy_routine_id);
843ΓåÆ      }
844ΓåÆ    }
845ΓåÆ
846ΓåÆ    const matches = matchCompletions(
847ΓåÆ      pendingItems,
848ΓåÆ      newWorkouts,
849ΓåÆ      (w) => nameToRoutineId.get(w.title) ?? null
850ΓåÆ    );
851ΓåÆ
852ΓåÆ    // Build workout ID ΓåÆ local date map for accurate completion dates
853ΓåÆ    const workoutDateMap = new Map<string, string>();
854ΓåÆ    for (const w of newWorkouts) {
855ΓåÆ      const d = tz
856ΓåÆ        ? new Date(w.start_time).toLocaleDateString("en-CA", { timeZone: tz })
857ΓåÆ        : w.start_time.slice(0, 10);
858ΓåÆ      workoutDateMap.set(w.id, d);
859ΓåÆ    }
860ΓåÆ
861ΓåÆ    for (const match of matches) {
862ΓåÆ      const completedDate = workoutDateMap.get(match.workoutId) ?? todayString(tz);
863ΓåÆ      await markQueueItemCompleted(env.DB, match.queueItemId, completedDate, match.workoutId);
864ΓåÆ    }
865ΓåÆ
866ΓåÆ    // Check for daily routine completion (use workout date, not sync date)
867ΓåÆ    const dailyRoutine = program.routines.find((r) => r.isDaily);
868ΓåÆ    if (dailyRoutine) {
869ΓåÆ      const dailyWorkout = workouts.find((w) => w.title === dailyRoutine.title);
870ΓåÆ      if (dailyWorkout) {
871ΓåÆ        const workoutDate = tz
872ΓåÆ          ? new Date(dailyWorkout.start_time).toLocaleDateString("en-CA", { timeZone: tz })
873ΓåÆ          : dailyWorkout.start_time.slice(0, 10);
874ΓåÆ        await updateDailyCompleted(env.DB, userId, workoutDate);
875ΓåÆ      }
876ΓåÆ    }
877ΓåÆ
878ΓåÆ    // Re-render today page
879ΓåÆ    return await handleTodaySSE(env, userId, tz);
880ΓåÆ  } catch (err) {
881ΓåÆ    const msg = escapeHtml(err instanceof Error ? err.message : "Pull failed");
882ΓåÆ    return sseResponse(
883ΓåÆ      patchElements(
884ΓåÆ        `<div class="card"><p style="color:var(--orange)">${msg}</p></div>`,
885ΓåÆ        { selector: "#content", mode: "prepend" }
886ΓåÆ      )
887ΓåÆ    );
888ΓåÆ  }
889ΓåÆ}
