891ΓåÆ/** POST /api/complete/:id ΓÇö manual complete, re-render today */
892ΓåÆasync function handleManualComplete(
893ΓåÆ  env: Env,
894ΓåÆ  userId: string,
895ΓåÆ  itemId: number,
896ΓåÆ  tz?: string
897ΓåÆ): Promise<Response> {
