139ΓåÆ    // First check existing D1 mapping
140ΓåÆ    const mappedId = existingMappings.get(a.routineId);
141ΓåÆ    if (mappedId) {
142ΓåÆ      return { programRoutineId: a.routineId, action: "update" as const, existingHevyRoutineId: mappedId, folderName: a.folderName };
143ΓåÆ    }
144ΓåÆ    // Then check Hevy by title + folder
145ΓåÆ    const targetFolderId = folderNameToId.get(a.folderName);
146ΓåÆ    if (targetFolderId !== undefined) {
147ΓåÆ      const match = existingHevyRoutines.find(
148ΓåÆ        (r) => r.title === a.routineTitle && r.folder_id === targetFolderId
149ΓåÆ      );
150ΓåÆ      if (match) {
151ΓåÆ        return { programRoutineId: a.routineId, action: "update" as const, existingHevyRoutineId: match.id, folderName: a.folderName };
152ΓåÆ      }
153ΓåÆ    }
154ΓåÆ    return { programRoutineId: a.routineId, action: "create" as const, folderName: a.folderName };
155ΓåÆ  });
