236ΓåÆ/**
237ΓåÆ * Normalize an exercise name for fuzzy matching:
238ΓåÆ * - Lowercase
239ΓåÆ * - Strip non-alphanumeric characters (spaces, hyphens, punctuation)
240ΓåÆ * - Strip a trailing 's' (basic singular/plural normalisation)
241ΓåÆ */
242ΓåÆfunction normalizeName(name: string): string {
243ΓåÆ  return name
244ΓåÆ    .toLowerCase()
245ΓåÆ    .replace(/[^a-z0-9]/g, "")
246ΓåÆ    .replace(/s$/, "");
247ΓåÆ}
248ΓåÆ
249ΓåÆ/**
250ΓåÆ * Attempt to automatically match our exercise templates to Hevy exercise
251ΓåÆ * template IDs using normalized title comparison. Supports partial matching
252ΓåÆ * (one normalized name contains the other).
253ΓåÆ *
254ΓåÆ * Returns a Map of our template ID ΓåÆ Hevy template ID for every template
255ΓåÆ * that could be matched.
256ΓåÆ */
257ΓåÆexport function autoMatchExercises(
258ΓåÆ  ourTemplates: ExerciseTemplate[],
259ΓåÆ  hevyTemplates: HevyExerciseTemplate[]
260ΓåÆ): Map<string, string> {
261ΓåÆ  const result = new Map<string, string>();
262ΓåÆ
263ΓåÆ  // Pre-normalize Hevy template titles
264ΓåÆ  const normalizedHevy = hevyTemplates.map((t) => ({
265ΓåÆ    id: t.id,
266ΓåÆ    norm: normalizeName(t.title),
267ΓåÆ  }));
268ΓåÆ
269ΓåÆ  for (const template of ourTemplates) {
270ΓåÆ    const normOurs = normalizeName(template.title);
271ΓåÆ
272ΓåÆ    // Prefer exact match first
273ΓåÆ    let matched = normalizedHevy.find((t) => t.norm === normOurs);
274ΓåÆ
275ΓåÆ    // Fall back to partial match (one contains the other)
276ΓåÆ    if (!matched) {
277ΓåÆ      matched = normalizedHevy.find(
278ΓåÆ        (t) => t.norm.includes(normOurs) || normOurs.includes(t.norm)
279ΓåÆ      );
280ΓåÆ    }
281ΓåÆ
282ΓåÆ    if (matched) {
283ΓåÆ      result.set(template.id, matched.id);
284ΓåÆ    }
285ΓåÆ  }
286ΓåÆ
287ΓåÆ  return result;
288ΓåÆ}
