 54ΓåÆ  private async request<T>(path: string, init?: RequestInit): Promise<T> {
 55ΓåÆ    const url = `${this.baseUrl}${path}`;
 56ΓåÆ    const res = await fetch(url, {
 57ΓåÆ      ...init,
 58ΓåÆ      headers: {
 59ΓåÆ        "api-key": this.apiKey,
 60ΓåÆ        "accept": "application/json",
 61ΓåÆ        "content-type": "application/json",
 62ΓåÆ        ...(init?.headers ?? {}),
 63ΓåÆ      },
 64ΓåÆ    });
 65ΓåÆ
 66ΓåÆ    if (res.status === 429) {
 67ΓåÆ      throw new Error("RATE_LIMITED");
 68ΓåÆ    }
 69ΓåÆ
 70ΓåÆ    if (!res.ok) {
 71ΓåÆ      const errorBody = await res.text().catch(() => "");
 72ΓåÆ      console.error(`Hevy API ${res.status} ${res.statusText} ${url}: ${errorBody}`);
 73ΓåÆ      throw new Error(`Hevy API error: ${res.status} ${res.statusText}: ${errorBody}`);
 74ΓåÆ    }
 75ΓåÆ
 76ΓåÆ    const text = await res.text();
 77ΓåÆ    try {
 78ΓåÆ      return JSON.parse(text) as T;
 79ΓåÆ    } catch {
 80ΓåÆ      console.error(`Hevy API response not JSON (${url}): ${text.slice(0, 200)}`);
 81ΓåÆ      throw new Error(`Hevy API returned non-JSON: ${text.slice(0, 100)}`);
 82ΓåÆ    }
