 8ΓåÆexport function generatePlaylist(
 9ΓåÆ  template: WeekTemplate,
10ΓåÆ  routines: Routine[],
11ΓåÆ  weeks: number
12ΓåÆ): PlaylistItem[] {
13ΓåÆ  const routineMap = new Map(routines.map((r) => [r.id, r]));
14ΓåÆ  const mainRoutineOrder: string[] = [];
15ΓåÆ
16ΓåÆ  for (const day of template.days) {
17ΓåÆ    if (!day.routineIDs) continue;
18ΓåÆ    for (const rid of day.routineIDs) {
19ΓåÆ      const routine = routineMap.get(rid);
20ΓåÆ      if (routine && !routine.isDaily) {
21ΓåÆ        mainRoutineOrder.push(rid);
22ΓåÆ      }
23ΓåÆ    }
24ΓåÆ  }
25ΓåÆ
26ΓåÆ  const playlist: PlaylistItem[] = [];
27ΓåÆ  for (let week = 0; week < weeks; week++) {
28ΓåÆ    for (const rid of mainRoutineOrder) {
29ΓåÆ      playlist.push({
30ΓåÆ        routine_id: rid,
31ΓåÆ        position: playlist.length,
32ΓåÆ      });
33ΓåÆ    }
34ΓåÆ  }
35ΓåÆ
36ΓåÆ  return playlist;
37ΓåÆ}
