 3ΓåÆconst MS_PER_WEEK = 7 * 24 * 60 * 60 * 1000;
 4ΓåÆ
 5ΓåÆ/** 1-based week number from start date. Always >= 1. */
 6ΓåÆexport function currentWeek(startDate: string, now: number = Date.now()): number {
 7ΓåÆ  const start = new Date(startDate).getTime();
 8ΓåÆ  if (isNaN(start)) return 1;
 9ΓåÆ  return Math.max(1, Math.floor((now - start) / MS_PER_WEEK) + 1);
10ΓåÆ}
