12ΓåÆ/** Find the active progression for a given week number. */
13ΓåÆexport function findActiveProgression(
14ΓåÆ  week: number,
15ΓåÆ  progressions: Progression[]
16ΓåÆ): Progression | undefined {
17ΓåÆ  return progressions.find(
18ΓåÆ    (p) =>
19ΓåÆ      p.weekStart != null &&
20ΓåÆ      p.weekEnd != null &&
21ΓåÆ      week >= p.weekStart &&
22ΓåÆ      week <= p.weekEnd
23ΓåÆ  );
24ΓåÆ}
