 12ΓåÆexport function programOverview(program: Program, user: UserRow | null, week: number | null): string {
 13ΓåÆ  const template = user
 14ΓåÆ    ? program.weekTemplates.find((t) => t.id === user.template_id)
 15ΓåÆ    : undefined;
 16ΓåÆ
 17ΓåÆ  const phase = week != null ? findActiveProgression(week, program.progressions) : undefined;
 18ΓåÆ  const exerciseCount = program.exerciseTemplates.length;
 19ΓåÆ  const routineCount = program.routines.filter((r) => !r.isDaily).length;
 20ΓåÆ
 21ΓåÆ  // Stats row
 22ΓåÆ  const stats: string[] = [];
 23ΓåÆ  if (week != null) stats.push(`<div class="stat-item"><div class="stat-value">${week}</div><div class="stat-label">Week</div></div>`);
 24ΓåÆ  stats.push(`<div class="stat-item"><div class="stat-value">${routineCount}</div><div class="stat-label">Routines</div></div>`);
 25ΓåÆ  stats.push(`<div class="stat-item"><div class="stat-value">${exerciseCount}</div><div class="stat-label">Exercises</div></div>`);
 26ΓåÆ  if (template) {
 27ΓåÆ    const daysPerWeek = template.days.filter((d) => d.routineIDs && d.routineIDs.length > 0).length;
