 32ΓåÆ
 33ΓåÆ  // Phase badge
 34ΓåÆ  const phaseBadge = phase
 35ΓåÆ    ? `<div style="display:inline-block;font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:var(--green);background:rgba(48,209,88,0.1);padding:4px 10px;border-radius:6px;margin-top:10px">${escapeHtml(phase.phaseName)}${phase.weekRange ? ` \u00B7 ${escapeHtml(phase.weekRange)}` : ""}</div>`
 36ΓåÆ    : "";
 37ΓåÆ
 38ΓåÆ  return `<div class="card">
 39ΓåÆ  <div class="card-label" style="color:var(--blue)">Program</div>
 40ΓåÆ  <div class="card-title">${escapeHtml(program.meta.title)}</div>
