 49ΓåÆexport function progressionsSection(progressions: Progression[], currentWk: number | null): string {
 50ΓåÆ  if (progressions.length === 0) return "";
 51ΓåÆ
 52ΓåÆ  const sorted = [...progressions].sort((a, b) => (a.weekStart ?? 0) - (b.weekStart ?? 0));
 53ΓåÆ
 54ΓåÆ  const items = sorted.map((p) => {
 55ΓåÆ    const isCurrent = currentWk != null && p.weekStart != null && p.weekEnd != null
 56ΓåÆ      && currentWk >= p.weekStart && currentWk <= p.weekEnd;
 57ΓåÆ    const isPast = currentWk != null && p.weekEnd != null && currentWk > p.weekEnd;
 58ΓåÆ    const dotColor = isCurrent ? "var(--green)" : isPast ? "var(--blue)" : "var(--text-tertiary)";
 59ΓåÆ    const cls = isCurrent ? " roadmap-current" : "";
 60ΓåÆ
 61ΓåÆ    return `<div class="roadmap-item${cls}">
 62ΓåÆ  <div class="roadmap-indicator" style="background:${dotColor}"></div>
 63ΓåÆ  <div>
 64ΓåÆ    <div class="roadmap-name">${escapeHtml(p.phaseName)}</div>
 65ΓåÆ    ${p.weekRange ? `<div class="roadmap-weeks">${escapeHtml(p.weekRange)}</div>` : ""}
 66ΓåÆ    ${p.focus ? `<div class="roadmap-summary">${escapeHtml(p.focus)}</div>` : ""}
 67ΓåÆ  </div>
 68ΓåÆ</div>`;
 69ΓåÆ  }).join("\n");
 70ΓåÆ
 71ΓåÆ  return `<div class="section-header">Phases</div>
 72ΓåÆ<div class="card">
 73ΓåÆ${items}
 74ΓåÆ</div>`;
 75ΓåÆ}
