 79ΓåÆexport function routinesSection(program: Program): string {
 80ΓåÆ  const templateMap = new Map(program.exerciseTemplates.map((t) => [t.id, t]));
 81ΓåÆ
 82ΓåÆ  const daily = program.routines.filter((r) => r.isDaily);
