100ΓåÆ      <div style="font-size:12px;color:var(--text-tertiary);margin-top:2px">${exCount} exercise${exCount !== 1 ? "s" : ""}${muscles ? ` \u00B7 ${escapeHtml(muscles)}` : ""}</div>
101ΓåÆ    </div>
102ΓåÆ    <svg style="width:16px;height:16px;color:var(--text-tertiary);flex-shrink:0" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="9 18 15 12 9 6"/></svg>
103ΓåÆ  </div>
104ΓåÆ</a>`;
105ΓåÆ  }
106ΓåÆ
107ΓåÆ  const dailyHtml = daily.length > 0
108ΓåÆ    ? daily.map((r) => routineCard(r)).join(`<div style="border-top:1px solid var(--separator)"></div>`)
109ΓåÆ    : "";
110ΓåÆ
111ΓåÆ  const sessionsHtml = sessions
