 20ΓåÆ  const now = Date.now();
 21ΓåÆ  if (cachedKeys && now < cacheExpiry) return cachedKeys;
 22ΓåÆ
 23ΓåÆ  const res = await fetch(CF_ACCESS_CERTS_URL);
 24ΓåÆ  if (!res.ok) throw new Error(`Failed to fetch Access certs: ${res.status}`);
