 44ΓåÆfunction base64UrlDecode(str: string): Uint8Array {
 45ΓåÆ  const padded = str.replace(/-/g, "+").replace(/_/g, "/");
 46ΓåÆ  const binary = atob(padded);
 47ΓåÆ  const bytes = new Uint8Array(binary.length);
 48ΓåÆ  for (let i = 0; i < binary.length; i++) {
 49ΓåÆ    bytes[i] = binary.charCodeAt(i);
 50ΓåÆ  }
 51ΓåÆ  return bytes;
 52ΓåÆ}
