 54ΓåÆasync function verifyAndDecode(jwt: string, expectedAud: string): Promise<{ email: string } | null> {
 55ΓåÆ  const parts = jwt.split(".");
 56ΓåÆ  if (parts.length !== 3) return null;
 57ΓåÆ
 58ΓåÆ  const header = JSON.parse(new TextDecoder().decode(base64UrlDecode(parts[0])));
 59ΓåÆ  const payload = JSON.parse(new TextDecoder().decode(base64UrlDecode(parts[1])));
 60ΓåÆ
 61ΓåÆ  // Verify audience
 62ΓåÆ  const aud = Array.isArray(payload.aud) ? payload.aud : [payload.aud];
 63ΓåÆ  if (!aud.includes(expectedAud)) return null;
 64ΓåÆ
 65ΓåÆ  // Verify expiry
 66ΓåÆ  const now = Math.floor(Date.now() / 1000);
 67ΓåÆ  if (payload.exp && payload.exp < now) return null;
 68ΓåÆ
 69ΓåÆ  // Verify signature
 70ΓåÆ  const keys = await getPublicKeys();
 71ΓåÆ  const key = keys.get(header.kid);
 72ΓåÆ  if (!key) return null;
 73ΓåÆ
