 75ΓåÆ  const signature = base64UrlDecode(parts[2]);
 76ΓåÆ
 77ΓåÆ  const valid = await crypto.subtle.verify(
 78ΓåÆ    "RSASSA-PKCS1-v1_5",
 79ΓåÆ    key,
 80ΓåÆ    signature,
 81ΓåÆ    signingInput
 82ΓåÆ  );
 83ΓåÆ
 84ΓåÆ  if (!valid) return null;
 85ΓåÆ
 86ΓåÆ  return { email: payload.email };
 87ΓåÆ}
