  }
}

/** POST /api/webhooks/hevy ΓÇö incoming event from Hevy (no app auth) */
async function handleWebhookEvent(
  request: Request,
  env: Env,
  ctx: ExecutionContext
): Promise<Response> {
  // Extract auth token ΓÇö Hevy sends it in the Authorization header as "Bearer <token>"
  // or as a plain token. Fall back to checking the request body.
  let authToken: string | null = null;
  const authHeader = request.headers.get("authorization");
  if (authHeader) {
    authToken = authHeader.replace(/^bearer\s+/i, "").trim();
  }

  if (!authToken) {
    // Try to extract from JSON body
    try {
      const body = await request.clone().json() as Record<string, unknown>;
      if (typeof body.auth_token === "string") {
        authToken = body.auth_token;
      }
    } catch {
      // Body not JSON or already consumed ΓÇö ignore
    }
  }

  if (!authToken) {
    return new Response("Unauthorized", { status: 401 });
  }

  const user = await getUserByWebhookToken(env.DB, authToken);
  if (!user) {
    return new Response("Unauthorized", { status: 401 });
  }

  // Acknowledge immediately ΓÇö Hevy expects a fast 2xx
  // Run sync in the background via waitUntil so the response is not delayed
  if (user.hevy_api_key) {
    ctx.waitUntil(
      performSync(env.DB, user.id, user.hevy_api_key).catch((err) => {
        console.error("Webhook sync failed for user", user.id, err instanceof Error ? err.message : err);
      })
    );
  }

  return new Response(null, { status: 200 });
}

/** POST /api/complete/:id ΓÇö manual complete, re-render today */
async function handleManualComplete(
  env: Env,
  userId: string,
  itemId: number,
  tz?: string
): Promise<Response> {
  if (!Number.isInteger(itemId)) {
    return new Response("Invalid item ID", { status: 400 });
  }
  const today = todayString(tz);
  await markQueueItemCompletedForUser(env.DB, itemId, userId, today);
  return await handleTodaySSE(env, userId, tz);
}

