export async function clearMappings(db: D1Database, userId: string): Promise<void> {
  await db.prepare("DELETE FROM exercise_template_mappings WHERE user_id = ?").bind(userId).run();
  await db.prepare("DELETE FROM routine_mappings WHERE user_id = ?").bind(userId).run();
}
```

## Step 3: Extract `activateProgram` from `handleSetup`

The existing `handleSetup` in `src/index.ts` does everything: validates, stores program, syncs exercise templates to Hevy, creates folders, reconciles routines, generates queue, and inserts queue items. 

Extract the core logic (everything after program validation and API key setup) into a reusable function:

```typescript
/**
 * Activate a program: store in D1, sync to Hevy, generate queue.
 * Reused by both initial setup and program import.
 */
async function activateProgram(
  db: D1Database,
  userId: string,
  program: Program,
  templateId: string,
  apiKey: string
): Promise<void> {
