868ΓåÆ+  );
869ΓåÆ+
870ΓåÆ+  // Build workout ID ΓåÆ local date map for accurate completion dates
871ΓåÆ+  const workoutDateMap = new Map<string, string>();
872ΓåÆ+  const workoutExercisesMap = new Map<string, string>();
873ΓåÆ+  for (const w of newWorkouts) {
