 67ΓåÆ/**
 68ΓåÆ * Format a single set as a compact string, e.g. "50kg ├ù 8", "45 sec", "8 reps".
 69ΓåÆ */
 70ΓåÆfunction formatSet(set: ActualSet): string {
 71ΓåÆ  if (set.duration_seconds != null) {
 72ΓåÆ    const secs = set.duration_seconds;
 73ΓåÆ    if (secs >= 60 && secs % 60 === 0) {
 74ΓåÆ      return `${secs / 60} min`;
 75ΓåÆ    }
 76ΓåÆ    return `${secs} sec`;
 77ΓåÆ  }
 78ΓåÆ  if (set.weight_kg != null && set.weight_kg > 0 && set.reps != null) {
 79ΓåÆ    return `${set.weight_kg}kg \u00d7 ${set.reps}`;
 80ΓåÆ  }
 81ΓåÆ  if (set.reps != null) {
 82ΓåÆ    return `${set.reps} reps`;
 83ΓåÆ  }
 84ΓåÆ  return "1 set";
 85ΓåÆ}
 86ΓåÆ
 87ΓåÆ/**
 88ΓåÆ * Render one exercise's sets as a compact inline string.
 89ΓåÆ * e.g. "45kg ├ù 8, 50kg ├ù 6, 50kg ├ù 5"
 90ΓåÆ */
 91ΓåÆfunction formatSetsInline(sets: ActualSet[]): string {
 92ΓåÆ  if (sets.length === 0) return "";
 93ΓåÆ  return sets.map(formatSet).join(", ");
 94ΓåÆ}
