 96ΓåÆ/**
 97ΓåÆ * Parse hevy_workout_data JSON, returning an empty array on failure.
 98ΓåÆ */
 99ΓåÆfunction parseWorkoutData(raw: string | null): HevyWorkoutExercise[] {
100ΓåÆ  if (!raw) return [];
101ΓåÆ  try {
102ΓåÆ    return JSON.parse(raw) as HevyWorkoutExercise[];
103ΓåÆ  } catch {
104ΓåÆ    return [];
105ΓåÆ  }
106ΓåÆ}
