108ΓåÆ/**
109ΓåÆ * Render the workout detail block for a completed item.
110ΓåÆ * Returns an empty string if there is no stored workout data.
111ΓåÆ */
112ΓåÆfunction workoutDetailBlock(hevy_workout_data: string | null): string {
113ΓåÆ  const exercises = parseWorkoutData(hevy_workout_data);
114ΓåÆ  if (exercises.length === 0) return "";
115ΓåÆ
116ΓåÆ  const totalSets = exercises.reduce((sum, e) => sum + e.sets.length, 0);
117ΓåÆ  const summary = `${exercises.length} exercise${exercises.length !== 1 ? "s" : ""}, ${totalSets} set${totalSets !== 1 ? "s" : ""}`;
118ΓåÆ
119ΓåÆ  const exerciseRows = exercises
120ΓåÆ    .map((ex) => {
121ΓåÆ      const setsLine = formatSetsInline(ex.sets);
122ΓåÆ      return `<div class="workout-exercise">
123ΓåÆ  <span class="workout-ex-name">${escapeHtml(ex.title)}</span>
124ΓåÆ  ${setsLine ? `<span class="workout-ex-sets">${escapeHtml(setsLine)}</span>` : ""}
125ΓåÆ</div>`;
126ΓåÆ    })
127ΓåÆ    .join("\n");
128ΓåÆ
129ΓåÆ  return `<details class="workout-details">
130ΓåÆ  <summary class="workout-summary">${escapeHtml(summary)}</summary>
131ΓåÆ  <div class="workout-exercises">
132ΓåÆ${exerciseRows}
133ΓåÆ  </div>
134ΓåÆ</details>`;
