274ΓåÆ      // ΓöÇΓöÇ POST /api/webhooks/unregister ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
275ΓåÆ      if (method === "POST" && path === "/api/webhooks/unregister") {
276ΓåÆ        return await handleWebhookUnregister(env, auth.userId, tz);
277ΓåÆ      }
278ΓåÆ
279ΓåÆ      // ΓöÇΓöÇ 404 ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
280ΓåÆ      return new Response("Not Found", { status: 404 });
281ΓåÆ    } catch (err) {
282ΓåÆ      if (err instanceof Response) return err;
283ΓåÆ      const message = err instanceof Error ? err.message : "Internal Server Error";
284ΓåÆ      const stack = err instanceof Error ? err.stack : "";
285ΓåÆ      console.error("Unhandled error:", message, stack);
286ΓåÆ      return new Response(message, { status: 500 });
287ΓåÆ    }
288ΓåÆ  },
289ΓåÆ};
