296ΓåÆasync function handleValidateProgram(request: Request): Promise<Response> {
297ΓåÆ  const body = (await request.json()) as Record<string, unknown>;
298ΓåÆ  // Fall back to bundled default program if none uploaded
299ΓåÆ  const programJsonStr = (body.programJson as string | undefined) || JSON.stringify(defaultProgramJson);
