304ΓåÆ  } catch {
305ΓåÆ    return sseResponse(
306ΓåÆ      patchElements(
307ΓåÆ        `<div class="card"><p style="color:var(--orange)">Invalid JSON file.</p></div>`,
308ΓåÆ        { selector: "#validation-result", mode: "inner" }
309ΓåÆ      )
310ΓåÆ    );
311ΓåÆ  }
312ΓåÆ
313ΓåÆ  const result = validateProgram(parsed);
314ΓåÆ  if (!result.valid) {
315ΓåÆ    const errorList = result.errors
316ΓåÆ      .map((e) => `<li>${escapeHtml(e)}</li>`)
317ΓåÆ      .join("");
318ΓåÆ    return sseResponse(
319ΓåÆ      patchElements(
320ΓåÆ        `<div class="card"><p style="color:var(--orange)">Validation errors:</p><ul style="margin:8px 0 0 16px;font-size:13px;color:var(--text-secondary)">${errorList}</ul></div>`,
321ΓåÆ        { selector: "#validation-result", mode: "inner" }
322ΓåÆ      )
