515ΓåÆ/** POST /api/setup ΓÇö store program, sync Hevy, create user, generate queue */
516ΓåÆasync function handleSetup(request: Request, env: Env, userId: string, urlTemplateId?: string, tz?: string): Promise<Response> {
517ΓåÆ  let body: { apiKey?: string; startDate?: string; templateId?: string; programJson?: string } = {};
518ΓåÆ  try {
519ΓåÆ    body = (await request.json()) as typeof body;
520ΓåÆ  } catch {
521ΓåÆ    // Body may be empty ΓÇö that's OK, template ID comes from URL
522ΓåÆ  }
523ΓåÆ
524ΓåÆ  const templateId = urlTemplateId ?? body.templateId;
525ΓåÆ  const startDate = body.startDate || todayString(tz);
526ΓåÆ  const apiKey = body.apiKey || undefined;
527ΓåÆ  // Fall back to bundled default program if none uploaded
528ΓåÆ  const programJsonStr = body.programJson || JSON.stringify(defaultProgramJson);
529ΓåÆ
530ΓåÆ  if (!templateId) {
531ΓåÆ    return new Response("Template ID is required", { status: 400 });
532ΓåÆ  }
533ΓåÆ
534ΓåÆ  // Parse and validate program
535ΓåÆ  let program: Program;
536ΓåÆ  try {
537ΓåÆ    const parsed = JSON.parse(programJsonStr);
538ΓåÆ    const result = validateProgram(parsed);
539ΓåÆ    if (!result.valid) {
540ΓåÆ      return new Response(`Invalid program: ${result.errors.join(", ")}`, { status: 400 });
541ΓåÆ    }
542ΓåÆ    program = result.program;
543ΓåÆ  } catch {
544ΓåÆ    return new Response("Invalid program JSON", { status: 400 });
545ΓåÆ  }
546ΓåÆ
547ΓåÆ  const template = program.weekTemplates.find((t) => t.id === templateId);
548ΓåÆ  if (!template) {
549ΓåÆ    return new Response("Invalid template ID", { status: 400 });
550ΓåÆ  }
551ΓåÆ
552ΓåÆ  // Validate API key against Hevy before proceeding
553ΓåÆ  if (apiKey) {
554ΓåÆ    try {
555ΓåÆ      const client = new HevyClient(apiKey);
556ΓåÆ      await client.getExerciseTemplates(1, 1);
557ΓåÆ    } catch {
558ΓåÆ      return sseResponse(
559ΓåÆ        patchElements(
560ΓåÆ          `<div class="card"><p style="color:var(--orange)">Invalid Hevy API key. Check your key in Hevy Settings &gt; Developer and try again.</p></div>`,
561ΓåÆ          { selector: "#content", mode: "prepend" }
562ΓåÆ        )
563ΓåÆ      );
564ΓåÆ    }
565ΓåÆ  }
566ΓåÆ
567ΓåÆ  // h. Upsert user (must exist before program insert due to FK constraint)
568ΓåÆ  await upsertUser(env.DB, {
569ΓåÆ    id: userId,
570ΓåÆ    active_program: program.meta.title,
571ΓåÆ    template_id: templateId,
572ΓåÆ    start_date: startDate,
573ΓåÆ    hevy_api_key: apiKey,
574ΓåÆ  });
575ΓåÆ
576ΓåÆ  // a-j. Store program, sync Hevy templates/routines, generate queue
577ΓåÆ  await activateProgram(env.DB, userId, program, programJsonStr, templateId, apiKey);
578ΓåÆ
579ΓåÆ  // k. Redirect to Today
580ΓåÆ  return sseResponse(executeScript("window.location.href = '/'"));
581ΓåÆ}
