939ΓåÆ  for (const r of allRoutines) {
940ΓåÆ    const key = `${r.title}::${r.folder_id ?? "none"}`;
941ΓåÆ    const list = byKey.get(key) ?? [];
942ΓåÆ    list.push(r);
943ΓåÆ    byKey.set(key, list);
