950ΓåÆ      routines.sort((a, b) => (b.updated_at ?? "").localeCompare(a.updated_at ?? ""));
951ΓåÆ      toDelete.push(...routines.slice(1).map((r) => r.id));
952ΓåÆ    }
953ΓåÆ  }
954ΓåÆ
955ΓåÆ  let deleted = 0;
956ΓåÆ  let failed = 0;
957ΓåÆ  for (const id of toDelete) {
958ΓåÆ    try {
