965ΓåÆ
966ΓåÆ  const msg = toDelete.length === 0
967ΓåÆ    ? "No duplicates found."
968ΓåÆ    : `Cleaned up ${deleted} duplicate(s)${failed > 0 ? `, ${failed} failed` : ""}.`;
