978ΓåÆ/**
979ΓåÆ * Core sync logic ΓÇö fetch recent Hevy workouts, match to pending queue items,
980ΓåÆ * mark completions, update daily CARs. Reused by both manual pull and webhook.
981ΓåÆ * Updates last_sync_at on successful completion.
982ΓåÆ */
983ΓåÆasync function performSync(db: D1Database, userId: string, apiKey: string, tz?: string): Promise<void> {
984ΓåÆ  const program = await loadProgram(db, userId);
985ΓåÆ  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
986ΓåÆ  const client = new HevyClient(apiKey);
987ΓåÆ
988ΓåÆ  const [workouts, items] = await Promise.all([
989ΓåÆ    client.getRecentWorkouts(),
990ΓåÆ    getQueueItems(db, userId),
991ΓåÆ  ]);
992ΓåÆ
993ΓåÆ  // Skip workouts already matched to a completed queue item
994ΓåÆ  const usedWorkoutIds = new Set(
995ΓåÆ    items.filter((i) => i.hevy_workout_id).map((i) => i.hevy_workout_id)
996ΓåÆ  );
997ΓåÆ  const newWorkouts = workouts.filter((w) => !usedWorkoutIds.has(w.id));
998ΓåÆ
999ΓåÆ  const pendingItems = items.filter((i) => i.status === "pending" && i.hevy_routine_id);

1000ΓåÆ
1001ΓåÆ  const nameToRoutineId = new Map<string, string>();
1002ΓåÆ  for (const item of pendingItems) {
1003ΓåÆ    const routine = routineMap.get(item.routine_id);
1004ΓåÆ    if (routine && item.hevy_routine_id) {
1005ΓåÆ      nameToRoutineId.set(routine.title, item.hevy_routine_id);
1006ΓåÆ    }
1007ΓåÆ  }
1008ΓåÆ
1009ΓåÆ  const matches = matchCompletions(
1010ΓåÆ    pendingItems,
1011ΓåÆ    newWorkouts,
1012ΓåÆ    (w) => nameToRoutineId.get(w.title) ?? null
1013ΓåÆ  );
1014ΓåÆ
1015ΓåÆ  // Build workout ID ΓåÆ local date map for accurate completion dates
1016ΓåÆ  const workoutDateMap = new Map<string, string>();
1017ΓåÆ  const workoutExercisesMap = new Map<string, string>();
1018ΓåÆ  for (const w of newWorkouts) {
1019ΓåÆ    const d = tz
1020ΓåÆ      ? new Date(w.start_time).toLocaleDateString("en-CA", { timeZone: tz })
1021ΓåÆ      : w.start_time.slice(0, 10);
1022ΓåÆ    workoutDateMap.set(w.id, d);
1023ΓåÆ    workoutExercisesMap.set(w.id, JSON.stringify(w.exercises));
1024ΓåÆ  }
1025ΓåÆ
1026ΓåÆ  for (const match of matches) {
1027ΓåÆ    const completedDate = workoutDateMap.get(match.workoutId) ?? todayString(tz);
1028ΓåÆ    const workoutData = workoutExercisesMap.get(match.workoutId);
1029ΓåÆ    await markQueueItemCompleted(db, match.queueItemId, completedDate, match.workoutId, workoutData);
1030ΓåÆ  }
1031ΓåÆ
1032ΓåÆ  // Check for daily routine completion (use workout date, not sync date)
1033ΓåÆ  const dailyRoutine = program.routines.find((r) => r.isDaily);
1034ΓåÆ  if (dailyRoutine) {
1035ΓåÆ    const dailyWorkout = workouts.find((w) => w.title === dailyRoutine.title);
1036ΓåÆ    if (dailyWorkout) {
1037ΓåÆ      const workoutDate = tz
1038ΓåÆ        ? new Date(dailyWorkout.start_time).toLocaleDateString("en-CA", { timeZone: tz })
1039ΓåÆ        : dailyWorkout.start_time.slice(0, 10);
1040ΓåÆ      await updateDailyCompleted(db, userId, workoutDate);
1041ΓåÆ    }
1042ΓåÆ  }
1043ΓåÆ
1044ΓåÆ  await updateLastSyncAt(db, userId, new Date().toISOString());
1045ΓåÆ}
