1142ΓåÆ/** POST /api/webhooks/hevy ΓÇö incoming event from Hevy (no app auth) */
1143ΓåÆasync function handleWebhookEvent(
1144ΓåÆ  request: Request,
1145ΓåÆ  env: Env,
1146ΓåÆ  ctx: ExecutionContext
1147ΓåÆ): Promise<Response> {
1148ΓåÆ  // Extract auth token ΓÇö Hevy sends it in the Authorization header as "Bearer <token>"
1149ΓåÆ  // or as a plain token. Fall back to checking the request body.
1150ΓåÆ  let authToken: string | null = null;
1151ΓåÆ  const authHeader = request.headers.get("authorization");
1152ΓåÆ  if (authHeader) {
1153ΓåÆ    authToken = authHeader.replace(/^bearer\s+/i, "").trim();
1154ΓåÆ  }
1155ΓåÆ
1156ΓåÆ  if (!authToken) {
1157ΓåÆ    // Try to extract from JSON body
1158ΓåÆ    try {
1159ΓåÆ      const body = await request.clone().json() as Record<string, unknown>;
1160ΓåÆ      if (typeof body.auth_token === "string") {
1161ΓåÆ        authToken = body.auth_token;
1162ΓåÆ      }
1163ΓåÆ    } catch {
1164ΓåÆ      // Body not JSON or already consumed ΓÇö ignore
1165ΓåÆ    }
1166ΓåÆ  }
1167ΓåÆ
1168ΓåÆ  if (!authToken) {
1169ΓåÆ    return new Response("Unauthorized", { status: 401 });
1170ΓåÆ  }
1171ΓåÆ
1172ΓåÆ  const user = await getUserByWebhookToken(env.DB, authToken);
1173ΓåÆ  if (!user) {
1174ΓåÆ    return new Response("Unauthorized", { status: 401 });
1175ΓåÆ  }
1176ΓåÆ
1177ΓåÆ  // Acknowledge immediately ΓÇö Hevy expects a fast 2xx
1178ΓåÆ  // Run sync in the background via waitUntil so the response is not delayed
1179ΓåÆ  if (user.hevy_api_key) {
1180ΓåÆ    ctx.waitUntil(
1181ΓåÆ      performSync(env.DB, user.id, user.hevy_api_key).catch((err) => {
1182ΓåÆ        console.error("Webhook sync failed for user", user.id, err instanceof Error ? err.message : err);
1183ΓåÆ      })
1184ΓåÆ    );
1185ΓåÆ  }
1186ΓåÆ
1187ΓåÆ  return new Response(null, { status: 200 });
1188ΓåÆ}
