 7ΓåÆexport function patchElements(html: string, opts?: PatchOptions): string {
 8ΓåÆ  let lines = `event: datastar-patch-elements\n`;
 9ΓåÆ  if (opts?.selector) lines += `data: selector ${opts.selector}\n`;
10ΓåÆ  if (opts?.mode) lines += `data: mode ${opts.mode}\n`;
11ΓåÆ  if (opts?.useViewTransition) lines += `data: useViewTransition true\n`;
12ΓåÆ  // Datastar v1: each continuation line must repeat "data: elements "
13ΓåÆ  const htmlLines = html.replace(/\n/g, "\ndata: elements ");
14ΓåÆ  lines += `data: elements ${htmlLines}\n\n`;
15ΓåÆ  return lines;
16ΓåÆ}
17ΓåÆ
18ΓåÆexport function patchSignals(signals: Record<string, unknown>): string {
