  ${b.target ? `<div class="benchmark-target">${escapeHtml(b.target)}</div>` : ""}
  <div class="benchmark-howto">${escapeHtml(b.howTo)}</div>
</div>`
    )
    .join("\n");

  return `<div class="section-header">Benchmarks</div>
<div class="card">
${items}
</div>`;
}

